import com.pinterest.ktlint.ruleset.standard.rules.FunctionSignatureRule.Companion.FUNCTION_BODY_EXPRESSION_WRAPPING_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.EnumSource

/**
 * Tests for issue https://github.com/pinterest/ktlint/issues/2028
 *
 * The function-signature rule should not merge annotated expressions with function signatures
 * as that would violate the annotation rule.
 */
class FunctionSignatureRuleAnnotatedExpressionTest {
    private val functionSignatureWrappingRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Nested
    inner class `Given a function with annotated expression body on separate line` {
        @ParameterizedTest(name = "bodyExpressionWrapping: {0}")
        @EnumSource(
            value = FunctionSignatureRule.FunctionBodyExpressionWrapping::class,
        )
        fun `Given that the body expression starts with an annotation then do not merge with function signature`(
            bodyExpressionWrapping: FunctionSignatureRule.FunctionBodyExpressionWrapping,
        ) {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                                                                                $EOL_CHAR
                private fun getErrorMessage(value: String): String =
                    @Suppress("DEPRECATION")
                    customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE_WITH_NO_REASON, value)
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .setMaxLineLength()
                .withEditorConfigOverride(FUNCTION_BODY_EXPRESSION_WRAPPING_PROPERTY to bodyExpressionWrapping)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a simple function with annotated expression body then do not merge`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                                    $EOL_CHAR
                fun foo(): String =
                    @Suppress("DEPRECATION")
                    bar()
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }

        @Test
        fun `Given a function with annotated expression body that would fit on same line then still do not merge`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER                                                                                                       $EOL_CHAR
                fun foo(): String =
                    @Suppress("DEPRECATION")
                    bar()
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given a multiline function signature with annotated expression body` {
        @Test
        fun `Given a multiline signature without explicit return type and annotated expression body then do not merge`() {
            val code =
                """
                // $MAX_LINE_LENGTH_MARKER       $EOL_CHAR
                fun functionSignatureTooLongForSingleLine(
                    a: Any,
                    b: Any
                ) =
                    @Suppress("DEPRECATION")
                    someResult
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .setMaxLineLength()
                .hasNoLintViolations()
        }
    }
}
"}

