                        nextCodeSiblingType = nextSibling?.elementType?.toString()
                        // Emit the type as an "error" so we can see it
                        emit(0, "EQ found: ${eqNode != null}, Next sibling type: $nextCodeSiblingType, Is ANNOTATED_EXPRESSION: ${nextSibling?.elementType == ANNOTATED_EXPRESSION}", false)
                    }
                }
            }
        }

        ruleAssertThat(code)
