import com.pinterest.ktlint.rule.engine.core.api.nextCodeSibling
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRuleBuilder
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.junit.jupiter.api.Test

/**
 * Diagnostic test to understand AST structure for annotated expressions
 */
class FunctionSignatureRuleAnnotatedExpressionDiagnosticTest {

    @Test
    fun `Diagnose AST structure for annotated expression body`() {
        val code =
            """
            fun getValue(): String =
                @Suppress("DEPRECATION")
                bar()
            """.trimIndent()

        var foundEqNode: ASTNode? = null
        var nextCodeSiblingType: String? = null

        val ruleAssertThat = assertThatRuleBuilder { emit ->
            object : com.pinterest.ktlint.rule.engine.core.api.Rule(
                ruleId = com.pinterest.ktlint.rule.engine.core.api.RuleId("test:diagnostic"),
                about = com.pinterest.ktlint.rule.engine.core.api.Rule.About(
                    maintainer = "test",
                    repositoryUrl = "test",
                    issueTrackerUrl = "test"
                ),
            ) {
                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                ) {
                    if (node.elementType == FUN) {
                        val eqNode = node.findChildByType(EQ)
                        foundEqNode = eqNode
                        val nextSibling = eqNode?.nextCodeSibling()
                        nextCodeSiblingType = nextSibling?.elementType?.toString()
                        // Emit the type as an "error" so we can see it
                        emit(0, "EQ found: ${eqNode != null}, Next sibling type: $nextCodeSiblingType, Is ANNOTATED_EXPRESSION: ${nextSibling?.elementType == ANNOTATED_EXPRESSION}", false)
                    }
                }
            }
        }

        ruleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(1, 1, "EQ found: true, Next sibling type: ANNOTATED_EXPRESSION, Is ANNOTATED_EXPRESSION: true")

        assertThat(foundEqNode).isNotNull
        assertThat(nextCodeSiblingType).isEqualTo("ANNOTATED_EXPRESSION")
    }

